INSERT INTO IDOM_HANDSON.RAW_DATA.ACTIVITY_LOGS (RAW_DATA)
SELECT PARSE_JSON(column1) FROM VALUES
  ('{"activity_id": "ACT0001", "negotiation_id": "N0024", "store_id": "S001", "customer_name": "上田浩二", "assigned_user_name": "鈴木一郎", "activity_type": "電話（受信）", "activity_date": "2026-03-25 10:15:00", "subject": "初回問合せ：ホンダ フィット 2019年式について", "body": "上田様より入電。Webで掲載中のホンダ フィット 2019年式（走行距離3.2万km）について問合せ。現在トヨタ ヴィッツに乗っており、燃費の良いコンパクトカーへの乗り換え希望。通勤用途で片道30km、月2回程度の遠出あり。予算は500万円前後。下取りも検討したいとのこと。週末の来店を提案、3/27(土)14時でアポ確定。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0002", "negotiation_id": "N0024", "store_id": "S001", "customer_name": "上田浩二", "assigned_user_name": "鈴木一郎", "activity_type": "来店対応", "activity_date": "2026-03-27 14:00:00", "subject": "来店ヒアリング・車両確認", "body": "上田様来店。ご家族（奥様）同伴。現車ヴィッツの状態確認→外装小キズあり、走行8.5万km。フィットの実車を確認いただき、内装の広さに好感触。ハイブリッドモデルの燃費性能（リッター30km）を説明。荷室の広さも気に入っていただけた。下取り査定額82万円を提示。奥様は色（白）を気に入っている様子。見積書を作成し、総額545万円（税込）で提示。「少し考えたい」とのことで、来週までにご連絡いただく約束。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0003", "negotiation_id": "N0024", "store_id": "S001", "customer_name": "上田浩二", "assigned_user_name": "鈴木一郎", "activity_type": "メール（送信）", "activity_date": "2026-03-27 18:30:00", "subject": "来店お礼・見積書送付", "body": "上田様へ来店お礼メール送信。見積書PDF添付。フィットの在庫状況として、同グレードの問合せが増えている旨をお伝え。下取り査定額の有効期限（2週間）についても記載。ご不明点があればいつでもご連絡くださいと添えた。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0004", "negotiation_id": "N0024", "store_id": "S001", "customer_name": "上田浩二", "assigned_user_name": "鈴木一郎", "activity_type": "電話（発信）", "activity_date": "2026-03-28 11:00:00", "subject": "フォローコール", "body": "上田様へ架電。奥様と相談中とのこと。価格面で「もう少し下がらないか」とご要望。下取り額の上乗せ（+5万円で87万円）を提案。また、今月中の成約であればコーティングサービスを無料で付けられることをご案内。「前向きに検討する」との回答。明日までにご連絡いただける見込み。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0005", "negotiation_id": "N0024", "store_id": "S001", "customer_name": "上田浩二", "assigned_user_name": "鈴木一郎", "activity_type": "電話（受信）", "activity_date": "2026-03-29 09:30:00", "subject": "成約連絡", "body": "上田様より入電。「購入を決めました」とのこと。最終条件：車両本体536万円、下取り87万円、コーティングサービス付き。本日午後に契約手続きのため来店予定。ローンは使わず現金一括とのこと。納車は4月第1週希望。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0006", "negotiation_id": "N0024", "store_id": "S001", "customer_name": "上田浩二", "assigned_user_name": "鈴木一郎", "activity_type": "契約手続き", "activity_date": "2026-03-29 15:00:00", "subject": "電子売契・契約完了", "body": "上田様来店、電子売契にて契約完了。車両本体536万円、諸費用込み総額545万円。下取りヴィッツ87万円。支払方法：現金一括。納車予定日：4/5(土)。任意保険の切替についてもご案内済み。保険担当に引継ぎ。上田様「対応が丁寧で安心して購入できた」とコメント。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0007", "negotiation_id": "N0529", "store_id": "S003", "customer_name": "片桐美咲", "assigned_user_name": "佐藤花子", "activity_type": "Web問合せ", "activity_date": "2026-04-07 08:45:00", "subject": "Web問合せ受信：トヨタ アクア", "body": "片桐様よりWebフォーム経由で問合せ。トヨタ アクア 2022年式に興味あり。現在車なし、初めての車購入。通勤で使いたいが、維持費が心配とのこと。予算は500万円以内。平日夕方か土日の来店希望。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0008", "negotiation_id": "N0529", "store_id": "S003", "customer_name": "片桐美咲", "assigned_user_name": "佐藤花子", "activity_type": "電話（発信）", "activity_date": "2026-04-07 10:30:00", "subject": "初回コンタクト：来店アポ調整", "body": "片桐様へ架電。お仕事の関係で平日は18時以降しか難しいとのこと。4/9(水)18:30でアポ確定。初めての車購入ということで、購入の流れや必要書類について簡単にご説明。駐車場の確保状況を確認→近くの月極を契約予定とのこと。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0009", "negotiation_id": "N0529", "store_id": "S003", "customer_name": "片桐美咲", "assigned_user_name": "佐藤花子", "activity_type": "来店対応", "activity_date": "2026-04-09 18:30:00", "subject": "来店ヒアリング・試乗", "body": "片桐様来店（お一人）。初めての車購入で緊張されている様子。丁寧にヒアリング実施。用途：通勤（片道15km）、休日の買い物。アクアの実車確認→サイズ感に安心。試乗実施（15分コース）。運転にやや不慣れだが「思ったより運転しやすい」との感想。燃費の良さ（リッター35km）を説明。見積り総額520万円を提示。ローンシミュレーション（60回払い、月々約8.7万円）もご案内。「親に相談してから決めたい」とのこと。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0010", "negotiation_id": "N0529", "store_id": "S003", "customer_name": "片桐美咲", "assigned_user_name": "佐藤花子", "activity_type": "電話（発信）", "activity_date": "2026-04-14 11:00:00", "subject": "フォローコール", "body": "片桐様へ架電。留守電にメッセージを残す。「ご検討状況いかがでしょうか。ご質問があればいつでもご連絡ください」と伝言。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0011", "negotiation_id": "N0529", "store_id": "S003", "customer_name": "片桐美咲", "assigned_user_name": "佐藤花子", "activity_type": "LINE", "activity_date": "2026-04-15 20:15:00", "subject": "LINEでのやり取り", "body": "片桐様よりLINE返信。「親に相談したところ、もう少し安い車にしたらと言われました。今回は見送ろうと思います。また機会があればよろしくお願いします」とのメッセージ。購入見送りの意思表示。丁寧にお礼を返信し、今後も良い車両があればご案内する旨をお伝え。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0012", "negotiation_id": "N0114", "store_id": "S001", "customer_name": "片桐美咲", "assigned_user_name": "藤田康平", "activity_type": "電話（受信）", "activity_date": "2026-04-06 13:20:00", "subject": "問合せ：スバル フォレスター", "body": "片桐様より入電。スバル フォレスター 2022年式について問合せ。現在ホンダ ヴェゼルに乗っているが、アウトドア趣味のため4WDの車に乗り換えたいとのこと。キャンプによく行くため荷室の広さ重視。予算は250万円。4/8(火)に来店希望。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0013", "negotiation_id": "N0114", "store_id": "S001", "customer_name": "片桐美咲", "assigned_user_name": "藤田康平", "activity_type": "来店対応", "activity_date": "2026-04-08 14:00:00", "subject": "来店ヒアリング・車両確認", "body": "片桐様来店。フォレスターの実車確認。荷室の広さに満足、ルーフレール付きでキャンプ用品の積載イメージが湧いた様子。AWDの走行性能についても詳しく説明。ただし、提示価格305万円に対し「予算オーバー」とのこと。当社の提示価格は市場相場として適正であることを説明。280万円まで下げられないかとの交渉あり。上長に相談する旨お伝えし、翌日回答する約束。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0014", "negotiation_id": "N0114", "store_id": "S001", "customer_name": "片桐美咲", "assigned_user_name": "藤田康平", "activity_type": "社内メモ", "activity_date": "2026-04-08 17:00:00", "subject": "値引き相談（店長）", "body": "店長の山田SV に相談。フォレスター2022年式、仕入れ価格と利益率を考慮し、最大290万円まで値引き可能との回答。これ以上の値引きは利益確保が困難。片桐様の希望280万円との差額10万円。下取りのヴェゼルで調整できないか検討。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0015", "negotiation_id": "N0114", "store_id": "S001", "customer_name": "片桐美咲", "assigned_user_name": "藤田康平", "activity_type": "電話（発信）", "activity_date": "2026-04-09 10:30:00", "subject": "価格回答", "body": "片桐様へ架電。290万円が最大限の値引きであることをお伝え。下取りヴェゼルの査定で+5万円の上乗せを提案（実質285万円相当）。片桐様「やっぱり280万円は厳しいですか…他のお店も見てみたいと思います」との回答。「他社さんの条件と比較いただいて、もし当社が良ければいつでもご連絡ください」とお伝えした。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0016", "negotiation_id": "N0114", "store_id": "S001", "customer_name": "片桐美咲", "assigned_user_name": "藤田康平", "activity_type": "電話（受信）", "activity_date": "2026-04-16 16:00:00", "subject": "他社購入の連絡", "body": "片桐様より入電。「他のお店で条件の合うフォレスターが見つかりましたので、そちらで購入することにしました。丁寧にご対応いただきありがとうございました」との連絡。価格不一致で不成約。他社（中古車販売大手B社）で278万円の同年式フォレスターを見つけた模様。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0017", "negotiation_id": "N0369", "store_id": "S007", "customer_name": "上田浩二", "assigned_user_name": "渡辺美穂", "activity_type": "電話（受信）", "activity_date": "2026-04-06 09:00:00", "subject": "急ぎの問合せ：フォレスター", "body": "上田様より入電。スバル フォレスター 2020年式について。事故で現在の車が全損になり、至急代わりの車が必要とのこと。保険会社との手続きも並行中。本日中に見に行きたいとの強い希望。10:30にアポ確定。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0018", "negotiation_id": "N0369", "store_id": "S007", "customer_name": "上田浩二", "assigned_user_name": "渡辺美穂", "activity_type": "来店対応", "activity_date": "2026-04-06 10:30:00", "subject": "来店・即日商談", "body": "上田様来店。事故の状況をヒアリング。前車はスバル レヴォーグ（2018年式）、保険金約150万円が見込まれる。フォレスターの実車確認→即座に「これにします」との意思表示。試乗も実施、AWD性能に満足。価格交渉：提示383万円に対し、「保険金を頭金にしたい、残りはローンで」とのこと。見積り作成、ローン審査の手続きに入る。最短納車を希望。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0019", "negotiation_id": "N0369", "store_id": "S007", "customer_name": "上田浩二", "assigned_user_name": "渡辺美穂", "activity_type": "電話（発信）", "activity_date": "2026-04-07 09:00:00", "subject": "ローン審査結果連絡", "body": "上田様へ架電。ローン審査通過の連絡。36回払い、月々約6.5万円。本日契約手続きに来店可能とのこと。午後イチで来店予定。レンタカーの手配状況も確認→保険会社負担で手配済み。納車まではレンタカーで対応可能とのこと。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0020", "negotiation_id": "N0369", "store_id": "S007", "customer_name": "上田浩二", "assigned_user_name": "渡辺美穂", "activity_type": "契約手続き", "activity_date": "2026-04-07 13:00:00", "subject": "契約完了・最短納車手配", "body": "上田様来店、契約完了。車両383万円、ローン36回。納車は4/10(木)で調整。整備・クリーニングを急ぎで手配。保険の切替手続きも同時進行。上田様「急な事故で困っていたが、迅速に対応してもらえて本当に助かった」とのこと。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0021", "negotiation_id": "N0513", "store_id": "S004", "customer_name": "杉山恵子", "assigned_user_name": "鈴木一郎", "activity_type": "来店対応", "activity_date": "2026-04-05 11:00:00", "subject": "飛び込み来店：プリウス問合せ", "body": "杉山様、予約なしで来店。店頭に展示中のプリウス 2021年式に目が留まった様子。軽くヒアリング→現在の車（ダイハツ ムーヴ）の車検が来月切れるため、乗り換えを検討中。ただし「まだ決めていない、情報収集中」との温度感。見積りは希望せず、カタログとお名刺をお渡し。連絡先をいただく。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0022", "negotiation_id": "N0513", "store_id": "S004", "customer_name": "杉山恵子", "assigned_user_name": "鈴木一郎", "activity_type": "電話（発信）", "activity_date": "2026-04-08 14:00:00", "subject": "フォローコール①", "body": "杉山様へ架電。不在、留守電にメッセージ。「先日はご来店ありがとうございました。プリウスについてご質問があればいつでもご連絡ください」と伝言。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0023", "negotiation_id": "N0513", "store_id": "S004", "customer_name": "杉山恵子", "assigned_user_name": "鈴木一郎", "activity_type": "メール（送信）", "activity_date": "2026-04-10 10:00:00", "subject": "フォローメール", "body": "杉山様へメール送信。プリウスの詳細スペック、燃費データ、在庫状況をまとめた資料を添付。ムーヴからの乗り換えであれば下取りも可能であることをご案内。車検期限が近いため、早めのご検討をお勧めする旨記載。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0024", "negotiation_id": "N0513", "store_id": "S004", "customer_name": "杉山恵子", "assigned_user_name": "鈴木一郎", "activity_type": "電話（発信）", "activity_date": "2026-04-15 11:00:00", "subject": "フォローコール②", "body": "杉山様へ架電。呼び出し音のみ、不在。留守電にメッセージを残す。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0025", "negotiation_id": "N0513", "store_id": "S004", "customer_name": "杉山恵子", "assigned_user_name": "鈴木一郎", "activity_type": "電話（発信）", "activity_date": "2026-04-22 10:30:00", "subject": "フォローコール③", "body": "杉山様へ架電。不在。3回目の架電でも繋がらず。メールの開封確認→未開封。今後のフォロー方針について店長と相談必要。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0026", "negotiation_id": "N0513", "store_id": "S004", "customer_name": "杉山恵子", "assigned_user_name": "鈴木一郎", "activity_type": "社内メモ", "activity_date": "2026-04-22 15:00:00", "subject": "連絡不通：対応方針", "body": "店長の高橋SV と相談。杉山様は3回架電・メール1通で一切反応なし。飛び込み来店で温度感も低かった。これ以上の積極的なアプローチは逆効果の可能性あり。1ヶ月後にDMを送付するリストに追加し、一旦クローズとする方針で合意。不成約（連絡不通）で処理。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0027", "negotiation_id": "N0059", "store_id": "S007", "customer_name": "杉山恵子", "assigned_user_name": "中村麻衣", "activity_type": "LINE", "activity_date": "2026-04-05 19:00:00", "subject": "LINE問合せ：プリウス", "body": "杉山様よりLINE友だち追加後、メッセージ。「プリウス 2021年式の在庫ありますか？仙台市内で探しています。ダイハツのムーヴから乗り換え予定です」。在庫確認→1台あり。写真を数枚送付し、来店をご提案。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0028", "negotiation_id": "N0059", "store_id": "S007", "customer_name": "杉山恵子", "assigned_user_name": "中村麻衣", "activity_type": "LINE", "activity_date": "2026-04-06 10:00:00", "subject": "LINEでの詳細やり取り", "body": "杉山様とLINEで複数回やり取り。走行距離、修復歴、タイヤの状態について質問あり→全て回答。「近所のディーラーでも見積もりを取っている」とのこと。競合はトヨタ認定中古車（U-Car）。4/12(土)来店でアポ確定。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0029", "negotiation_id": "N0059", "store_id": "S007", "customer_name": "杉山恵子", "assigned_user_name": "中村麻衣", "activity_type": "来店対応", "activity_date": "2026-04-12 13:00:00", "subject": "来店・試乗・見積り", "body": "杉山様来店。プリウスの実車確認、試乗実施。「乗り心地が良い」「ムーヴとは全然違う」と好感触。見積り：車両210万円、諸費用込み約225万円。下取りムーヴ65万円。ローン提案（36回、月4.4万円）。杉山様「トヨタの認定中古車と比べて検討したい。向こうは保証が手厚いので」との発言。当社の保証プラン（最長3年）について詳しく説明。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0030", "negotiation_id": "N0059", "store_id": "S007", "customer_name": "杉山恵子", "assigned_user_name": "中村麻衣", "activity_type": "LINE", "activity_date": "2026-04-18 12:00:00", "subject": "LINEフォロー", "body": "杉山様へLINEでフォロー。「ご検討状況いかがですか？当社の保証プランの詳細資料をお送りしましょうか？」と送信。既読つくも返信なし。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0031", "negotiation_id": "N0059", "store_id": "S007", "customer_name": "杉山恵子", "assigned_user_name": "中村麻衣", "activity_type": "LINE", "activity_date": "2026-04-25 14:00:00", "subject": "LINE：他社購入の報告", "body": "杉山様よりLINE。「色々考えたのですが、トヨタの認定中古車でプリウスを購入することにしました。保証内容が決め手でした。ご丁寧にありがとうございました」。未成約（他社購入）。トヨタ認定中古車の2年保証に対し、当社の保証説明が十分でなかった可能性。保証プランの訴求方法を改善すべき。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0032", "negotiation_id": "N0335", "store_id": "S003", "customer_name": "寺田直樹", "assigned_user_name": "石井由美", "activity_type": "電話（受信）", "activity_date": "2026-04-03 11:00:00", "subject": "問合せ：日産ノート e-POWER", "body": "寺田様より入電。日産ノート e-POWER 2022年式について。セカンドカーとして検討中。奥様の買い物・送迎用途。予算は350万円以内を希望。4/5(土)来店でアポ。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0033", "negotiation_id": "N0335", "store_id": "S003", "customer_name": "寺田直樹", "assigned_user_name": "石井由美", "activity_type": "来店対応", "activity_date": "2026-04-05 10:30:00", "subject": "来店・奥様同伴", "body": "寺田様ご夫婦で来店。奥様が主に運転されるとのこと。ノートe-POWERの実車確認。奥様は「コンパクトで運転しやすい」と好評。e-POWERの静粛性にも驚かれた。ただし、提示価格398万円に対し「350万円が上限」と明確におっしゃる。差額約50万円。値引き交渉の余地を検討するため、翌週に回答することに。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0034", "negotiation_id": "N0335", "store_id": "S003", "customer_name": "寺田直樹", "assigned_user_name": "石井由美", "activity_type": "社内メモ", "activity_date": "2026-04-05 17:00:00", "subject": "値引き検討", "body": "店長と相談。仕入れ価格から逆算し、最大値引きは380万円（18万円引き）。寺田様の希望350万円には30万円届かない。下取り車なし。これ以上の値引きは困難。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0035", "negotiation_id": "N0335", "store_id": "S003", "customer_name": "寺田直樹", "assigned_user_name": "石井由美", "activity_type": "電話（発信）", "activity_date": "2026-04-07 10:00:00", "subject": "価格回答", "body": "寺田様へ架電。最大限の値引きとして380万円をご提示。寺田様「うーん、やっぱり350万円は無理ですか…。少し考えさせてください」。1週間ほど検討期間をいただく。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0036", "negotiation_id": "N0335", "store_id": "S003", "customer_name": "寺田直樹", "assigned_user_name": "石井由美", "activity_type": "電話（発信）", "activity_date": "2026-04-14 11:00:00", "subject": "フォローコール", "body": "寺田様へ架電。「やはり予算的に厳しいので、今回は見送ります。もう少し安い年式のものが出たら教えてください」との回答。不成約（価格不一致）。2020年式以前のノートが入荷した際にご連絡するリストに追加。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0037", "negotiation_id": "N0415", "store_id": "S010", "customer_name": "大西康平", "assigned_user_name": "小林翔太", "activity_type": "紹介", "activity_date": "2026-04-05 09:30:00", "subject": "紹介案件：ハリアー", "body": "既存顧客の田中様からの紹介で大西様の情報を受領。ハリアー 2020年式に興味あり。田中様「大西は車好きで、SUVが欲しいと言っていた」とのコメント。大西様へ架電しアポ調整。4/8(火)19時で来店アポ。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0038", "negotiation_id": "N0415", "store_id": "S010", "customer_name": "大西康平", "assigned_user_name": "小林翔太", "activity_type": "来店対応", "activity_date": "2026-04-08 19:00:00", "subject": "来店・車両確認", "body": "大西様来店。仕事帰りで19時来店。ハリアーの実車確認。グレード・装備に詳しく、かなりの車好き。「他の店でも見ている」とのこと。具体的にはディーラー認定中古車とカーセンサー掲載車を比較中。見積り275万円を提示。「まぁ、相場通りですね」とクールな反応。即決はせず「連絡します」と帰られた。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0039", "negotiation_id": "N0415", "store_id": "S010", "customer_name": "大西康平", "assigned_user_name": "小林翔太", "activity_type": "電話（発信）", "activity_date": "2026-04-12 10:00:00", "subject": "フォローコール①", "body": "大西様へ架電。不在。留守電なし（留守電設定されていない模様）。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0040", "negotiation_id": "N0415", "store_id": "S010", "customer_name": "大西康平", "assigned_user_name": "小林翔太", "activity_type": "電話（発信）", "activity_date": "2026-04-18 15:00:00", "subject": "フォローコール②", "body": "大西様へ架電。不在。SMSでメッセージを送信。「先日はご来店ありがとうございました。ハリアーのご検討状況はいかがでしょうか？」と送信。既読確認不可。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0041", "negotiation_id": "N0415", "store_id": "S010", "customer_name": "大西康平", "assigned_user_name": "小林翔太", "activity_type": "社内メモ", "activity_date": "2026-04-25 10:00:00", "subject": "連絡不通：未成約処理", "body": "大西様、来店後2週間以上経過、架電2回・SMS1通で反応なし。紹介元の田中様に確認→「最近忙しいみたいで、車の話は聞いていない」とのこと。他社で購入した可能性もあるが確認不能。未成約（連絡不通）で処理。紹介元にお礼を伝達済み。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0042", "negotiation_id": "N0448", "store_id": "S003", "customer_name": "清水拓也", "assigned_user_name": "高橋健一", "activity_type": "電話（受信）", "activity_date": "2026-03-30 10:00:00", "subject": "問合せ：プリウス格安車両", "body": "清水様より入電。Webで掲載中のプリウス 2020年式（102万円）について。「この価格で本当に大丈夫ですか？」と品質面を心配されている。走行12万kmだが整備済みであること、当社の保証付きであることを説明。来店日程調整→3/31(月)14時。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0043", "negotiation_id": "N0448", "store_id": "S003", "customer_name": "清水拓也", "assigned_user_name": "高橋健一", "activity_type": "来店対応", "activity_date": "2026-03-31 14:00:00", "subject": "来店・即日成約", "body": "清水様来店。プリウスの実車確認。走行12万kmだが、エンジン・ミッション・足回りの状態を丁寧に説明。試乗実施→「全然問題ない」との感想。「会社の通勤用なのでとにかく安くて燃費が良ければいい」とのこと。値引き交渉：提示102万円→端数切って100万円で合意。即日仮契約。法人リースの可能性も確認→個人購入で確定。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0044", "negotiation_id": "N0448", "store_id": "S003", "customer_name": "清水拓也", "assigned_user_name": "高橋健一", "activity_type": "電話（発信）", "activity_date": "2026-04-02 09:00:00", "subject": "書類確認・納車日調整", "body": "清水様へ架電。必要書類（印鑑証明、車庫証明）の確認。車庫証明はご自身で取得予定。納車は4/6(日)で調整。ナンバープレートの希望番号確認→特になし。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0045", "negotiation_id": "N0448", "store_id": "S003", "customer_name": "清水拓也", "assigned_user_name": "高橋健一", "activity_type": "契約手続き", "activity_date": "2026-04-06 10:00:00", "subject": "納車完了", "body": "清水様来店、納車完了。総額108万円（諸費用込み）。現金払い。取扱説明、メンテナンスパック（オイル交換3回付き）のご案内。清水様「これだけ安くて状態が良いなら大満足です。また何かあればお願いします」とのコメント。紹介カードをお渡し。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0046", "negotiation_id": "N0332", "store_id": "S009", "customer_name": "野村康平", "assigned_user_name": "森田沙織", "activity_type": "Web問合せ", "activity_date": "2026-04-04 22:00:00", "subject": "深夜Web問合せ：フォレスター", "body": "野村様よりWebフォーム。スバル フォレスター 2024年式（530万円）について。「高年式のフォレスターを探している。現車はCX-5。できれば今月中に乗り換えたい」とのコメント。電話番号あり、メールアドレスあり。翌朝対応予定。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0047", "negotiation_id": "N0332", "store_id": "S009", "customer_name": "野村康平", "assigned_user_name": "森田沙織", "activity_type": "電話（発信）", "activity_date": "2026-04-05 09:30:00", "subject": "初回架電", "body": "野村様へ架電。お出になったが「今仕事中なので後で折り返します」と短い会話で終了。折り返し待ち。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0048", "negotiation_id": "N0332", "store_id": "S009", "customer_name": "野村康平", "assigned_user_name": "森田沙織", "activity_type": "社内メモ", "activity_date": "2026-05-03 10:00:00", "subject": "折り返しなし：未成約処理", "body": "野村様、初回架電から約1ヶ月経過。折り返しなし。メール1通送信（4/10）も反応なし。Web問合せの温度感が高そうだったが、架電タイミングが悪かった可能性。今後、Web問合せに対する初回レスポンス時間の短縮と、夜間問合せへの翌朝一番対応を徹底すべき。未成約（連絡不通）で処理。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0049", "negotiation_id": "N0434", "store_id": "S005", "customer_name": "相川健太", "assigned_user_name": "小林翔太", "activity_type": "LINE", "activity_date": "2026-04-06 21:30:00", "subject": "LINE問合せ：アクア", "body": "相川様よりLINE。「トヨタ アクア 2020年式ってまだありますか？免許取ったばかりで初めての車です。予算200万くらいで探してます」。在庫あり。写真と基本スペックを送信。相川様は22歳、社会人1年目とのこと。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0050", "negotiation_id": "N0434", "store_id": "S005", "customer_name": "相川健太", "assigned_user_name": "小林翔太", "activity_type": "LINE", "activity_date": "2026-04-07 12:30:00", "subject": "LINEやり取り：質問対応", "body": "相川様よりLINE複数質問。「保険料ってどのくらいかかりますか？」「任意保険は入らないとダメですか？」「ローンは組めますか？新卒でも大丈夫ですか？」→すべて丁寧に回答。若年層向けの保険プラン、新卒でも審査通りやすいローン会社（最大84回払い）をご紹介。来店を提案→4/10(木)19時で確定。", "created_at": "2026-04-07 21:17:43.495000"}');

INSERT INTO IDOM_HANDSON.RAW_DATA.ACTIVITY_LOGS (RAW_DATA)
SELECT PARSE_JSON(column1) FROM VALUES
  ('{"activity_id": "ACT0051", "negotiation_id": "N0434", "store_id": "S005", "customer_name": "相川健太", "assigned_user_name": "小林翔太", "activity_type": "来店対応", "activity_date": "2026-04-10 19:00:00", "subject": "来店・ご両親同伴", "body": "相川様来店。ご両親（父母）同伴。初めての車購入で不安そうな様子。お父様は車に詳しく、エンジンルームやタイヤの状態を確認。試乗はお父様が運転→「状態は良いですね」とコメント。見積り提示：車両190万円、諸費用込み約210万円。ローン60回（月3.5万円）。お父様「もう少し下がらない？」→端数を切って総額205万円で提示。ご家族で相談。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0052", "negotiation_id": "N0434", "store_id": "S005", "customer_name": "相川健太", "assigned_user_name": "小林翔太", "activity_type": "LINE", "activity_date": "2026-04-12 18:00:00", "subject": "LINE：購入決定", "body": "相川様よりLINE。「親とも話して、購入することに決めました！いつ契約に行けばいいですか？」。4/15(火)19時で契約アポ。必要書類リストをLINEで送付。住民票、印鑑証明の取得方法もご案内（初めてのため不慣れ）。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0053", "negotiation_id": "N0434", "store_id": "S005", "customer_name": "相川健太", "assigned_user_name": "小林翔太", "activity_type": "契約手続き", "activity_date": "2026-04-15 19:00:00", "subject": "契約完了・保険同時加入", "body": "相川様来店、契約完了。総額205万円、60回ローン。初めての車ということで、任意保険もセットでご加入（車両保険付きプラン、月12,000円）。納車は4/22(火)予定。ETC取付とドライブレコーダー後付けも希望→納車時に施工予定。相川様「自分の車が持てるの嬉しいです！」とテンション高め。お父様からも「安心してお任せできました」とのコメント。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0054", "negotiation_id": "N0083", "store_id": "S004", "customer_name": "黒田麻衣", "assigned_user_name": "井上大輔", "activity_type": "電話（受信）", "activity_date": "2026-04-04 14:00:00", "subject": "問合せ：マツダ CX-5", "body": "黒田様より入電。マツダ CX-5 2024年式について。現在日産エクストレイルに乗っているが、マツダのデザインが気になるとのこと。「CX-5の走りが好きだと友人に勧められた」。週末の来店希望。4/6(日)11時でアポ。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0055", "negotiation_id": "N0083", "store_id": "S004", "customer_name": "黒田麻衣", "assigned_user_name": "井上大輔", "activity_type": "来店対応", "activity_date": "2026-04-06 11:00:00", "subject": "来店・試乗・比較検討", "body": "黒田様来店（お一人）。30代女性、アクティブな印象。CX-5の実車確認→「やっぱりデザインが素敵」。ディーゼルモデルのトルク感を試乗で体感→「これは全然違う！エクストレイルよりキビキビ走る」と興奮気味。i-ACTIVSENSEの安全装備についても詳しく説明。見積り345万円。下取りエクストレイル約30万円。「主人に相談してから」とのこと。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0056", "negotiation_id": "N0083", "store_id": "S004", "customer_name": "黒田麻衣", "assigned_user_name": "井上大輔", "activity_type": "電話（発信）", "activity_date": "2026-04-09 11:00:00", "subject": "フォローコール", "body": "黒田様へ架電。ご主人も興味があるとのことで、もう一度来店して一緒に試乗したいとのリクエスト。4/13(日)10時で再来店アポ。ご主人用に別途見積りも用意しておく旨お伝え。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0057", "negotiation_id": "N0083", "store_id": "S004", "customer_name": "黒田麻衣", "assigned_user_name": "井上大輔", "activity_type": "来店対応", "activity_date": "2026-04-13 10:00:00", "subject": "再来店・ご主人同伴・成約", "body": "黒田様ご夫婦で来店。ご主人も試乗→「確かにこれはいい車だ」とのこと。価格交渉：ご主人が「340万円にしてもらえないか」→下取り上乗せで実質335万円相当で合意。即日仮契約。ご主人「妻がこんなに気に入っている車は初めてだ」と笑顔。保険の見直しも同時にご提案→検討中。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0058", "negotiation_id": "N0080", "store_id": "S010", "customer_name": "中島翔太", "assigned_user_name": "松本美咲", "activity_type": "電話（受信）", "activity_date": "2026-04-03 16:00:00", "subject": "問合せ：アルファード", "body": "中島様より入電。トヨタ アルファード 2021年式について。4人家族（お子様2人、3歳と1歳）で、ミニバンに乗り換え検討中。現車はトヨタ シエンタ。予算は450万円前後。下取りも希望。4/6(日)来店予定。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0059", "negotiation_id": "N0080", "store_id": "S010", "customer_name": "中島翔太", "assigned_user_name": "松本美咲", "activity_type": "来店対応", "activity_date": "2026-04-06 13:00:00", "subject": "来店・家族全員で確認", "body": "中島様ご家族4人で来店。お子様が小さいため、チャイルドシートの設置確認や乗り降りのしやすさを重点的にチェック。奥様はスライドドアの開口部の広さに安心。3列目シートの広さも確認。見積り：車両465万円、下取りシエンタ114万円。差額351万円。ローンシミュレーション提示。中島様「ちょっと思ったより高いな…シエンタの下取りがもっと高ければ…」。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0060", "negotiation_id": "N0080", "store_id": "S010", "customer_name": "中島翔太", "assigned_user_name": "松本美咲", "activity_type": "電話（発信）", "activity_date": "2026-04-10 10:00:00", "subject": "フォローコール", "body": "中島様へ架電。検討中とのこと。「実は奥さんから、3人目を考えているからもう少し先でもいいのではと言われた」との新情報。購入意欲が下がっている印象。「お子様が増えた後の方が、サイズ感の判断もしやすいかもしれませんね」とアドバイス。急かさず、時期が来たらご連絡くださいとお伝え。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0061", "negotiation_id": "N0080", "store_id": "S010", "customer_name": "中島翔太", "assigned_user_name": "松本美咲", "activity_type": "電話（発信）", "activity_date": "2026-04-20 11:00:00", "subject": "フォロー②", "body": "中島様へ架電。「やっぱり今回は見送ることにしました。もう一人生まれてから改めて考えます。その時はまた相談させてください」との回答。未成約（購入見送り）。将来のフォローリスト（半年後）に追加。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0062", "negotiation_id": "N0452", "store_id": "S004", "customer_name": "片桐美咲", "assigned_user_name": "田中太郎", "activity_type": "電話（受信）", "activity_date": "2026-03-31 09:00:00", "subject": "問合せ：アルファード 2021年式", "body": "片桐様より入電。トヨタ アルファード 2021年式に問合せ。現在トヨタ ヴェルファイアに乗っており、同系統での乗り換え。「ヴェルファイアの下取り額次第で検討したい」とのこと。下取り査定のため来店を提案。4/3(木)来店。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0063", "negotiation_id": "N0452", "store_id": "S004", "customer_name": "片桐美咲", "assigned_user_name": "田中太郎", "activity_type": "来店対応", "activity_date": "2026-04-03 14:00:00", "subject": "来店・下取り査定・価格交渉", "body": "片桐様来店。ヴェルファイア（2019年式、走行5.8万km）の下取り査定実施→195万円を提示。片桐様「もう少し高くならないか。他社では210万円と言われた」と交渉。アルファードの車両価格393万円と合わせると、実質負担198万円。片桐様の希望は実質150万円以内。「下取り額を上げるか、車両価格を下げるか」と要望。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0064", "negotiation_id": "N0452", "store_id": "S004", "customer_name": "片桐美咲", "assigned_user_name": "田中太郎", "activity_type": "社内メモ", "activity_date": "2026-04-03 17:30:00", "subject": "価格調整の社内協議", "body": "店長と協議。下取りは最大200万円まで上乗せ可能。車両値引きは最大373万円まで（20万円引き）。合計で実質173万円が限界。片桐様の150万円希望には23万円の乖離。かなり厳しい交渉。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0065", "negotiation_id": "N0452", "store_id": "S004", "customer_name": "片桐美咲", "assigned_user_name": "田中太郎", "activity_type": "電話（発信）", "activity_date": "2026-04-05 10:00:00", "subject": "最終価格提示", "body": "片桐様へ架電。下取り200万円+車両値引き373万円=実質173万円を最終提示。片桐様「うーん、まだ23万円高い…。オプションか何かで調整できませんか？」。フロアマット・ドアバイザーセット（約5万円相当）のサービスを提案。「ちょっと考えます」。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0066", "negotiation_id": "N0452", "store_id": "S004", "customer_name": "片桐美咲", "assigned_user_name": "田中太郎", "activity_type": "電話（発信）", "activity_date": "2026-04-15 11:00:00", "subject": "フォローコール", "body": "片桐様へ架電。「他の店でもう少し安いアルファードが見つかったので、そちらにしようと思います」との回答。不成約（価格不一致）。下取り額の競合が厳しい状況。今後同様のケースでは、初回査定時に競合他社の査定額をヒアリングし、先手で対応する必要あり。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0067", "negotiation_id": "N0378", "store_id": "S009", "customer_name": "高木沙織", "assigned_user_name": "渡辺美穂", "activity_type": "電話（受信）", "activity_date": "2026-03-27 15:00:00", "subject": "問合せ：ヴェゼル", "body": "高木様より入電。ホンダ ヴェゼル 2021年式について。現在ホンダ フリードに乗っている。「子供が大きくなったのでフリードは卒業」とのこと。SUVに憧れがあるが運転に自信がないとのこと。来店して実車を見たい。3/29(土)13時。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0068", "negotiation_id": "N0378", "store_id": "S009", "customer_name": "高木沙織", "assigned_user_name": "渡辺美穂", "activity_type": "来店対応", "activity_date": "2026-03-29 13:00:00", "subject": "来店・試乗・安心訴求", "body": "高木様来店（お一人）。ヴェゼルの実車確認。「思ったより大きくない、フリードとそんなに変わらない」と安心された様子。Honda SENSING（衝突軽減ブレーキ等）の安全装備を詳しく説明。試乗ではバックカメラとパーキングセンサーの動作を実演→「これなら安心」。見積り280万円、下取りフリード73万円。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0069", "negotiation_id": "N0378", "store_id": "S009", "customer_name": "高木沙織", "assigned_user_name": "渡辺美穂", "activity_type": "電話（発信）", "activity_date": "2026-04-01 10:00:00", "subject": "契約意思確認", "body": "高木様へ架電。「購入します！」とのこと。4/5(土)に契約手続きで来店。保険についてもご案内→現在の保険が来月満期のため、切替のタイミングとしても最適。保険担当に引継ぎ準備。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0070", "negotiation_id": "N0378", "store_id": "S009", "customer_name": "高木沙織", "assigned_user_name": "渡辺美穂", "activity_type": "契約手続き", "activity_date": "2026-04-05 10:00:00", "subject": "契約完了・保険切替成功", "body": "高木様来店、契約完了。総額290万円（諸費用込み）、下取り73万円、差額217万円をローン48回。保険も同時に切替成功→車両保険付きフルカバープラン、年間78,000円。弁護士特約・ロードサービス特約付き。保険付帯率向上に貢献。高木様「全部まとめて対応してもらえて楽でした」。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0071", "negotiation_id": "N0208", "store_id": "S006", "customer_name": "上田浩二", "assigned_user_name": "井上大輔", "activity_type": "LINE", "activity_date": "2026-04-05 08:00:00", "subject": "LINE問合せ：CX-5", "body": "上田様よりLINE。「マツダ CX-5 2023年式の在庫情報を教えてください。札幌市内で探しています。現在レヴォーグに乗っていますが、マツダに興味が出てきました」。在庫写真3枚と車両詳細スペックを即座に返信。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0072", "negotiation_id": "N0208", "store_id": "S006", "customer_name": "上田浩二", "assigned_user_name": "井上大輔", "activity_type": "LINE", "activity_date": "2026-04-05 12:00:00", "subject": "LINE：試乗予約", "body": "上田様とLINEで10往復ほどのやり取り。内装の質感、マツダコネクト（ナビ）の操作性、ディーゼルの燃費実績について詳しく質問あり。すべて写真付きで回答。「実際に見てみたい。今週末に行けます」→4/6(日)14時で来店予約。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0073", "negotiation_id": "N0208", "store_id": "S006", "customer_name": "上田浩二", "assigned_user_name": "井上大輔", "activity_type": "来店対応", "activity_date": "2026-04-06 14:00:00", "subject": "来店・試乗・好感触", "body": "上田様来店。CX-5の試乗コース（約20分）を実施。「ディーゼルのトルク感が最高。レヴォーグとは違う楽しさがある」と大満足。内装の質感にも「これが中古車の価格で買えるのはお得」とコメント。見積り408万円、下取りレヴォーグなし（事故で全損済み、別案件N0369で処理済み）。ローン提案。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0074", "negotiation_id": "N0208", "store_id": "S006", "customer_name": "上田浩二", "assigned_user_name": "井上大輔", "activity_type": "LINE", "activity_date": "2026-04-10 20:00:00", "subject": "LINE：値引き交渉", "body": "上田様よりLINE。「気に入っているのですが、400万円ジャストにしてもらえませんか？」。翌朝店長と相談の上、回答予定と返信。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0075", "negotiation_id": "N0208", "store_id": "S006", "customer_name": "上田浩二", "assigned_user_name": "井上大輔", "activity_type": "LINE", "activity_date": "2026-04-11 10:00:00", "subject": "LINE：成約", "body": "上田様へ回答。「403万円まで値引き可能です。加えてオイル交換3回分をサービスさせていただきます」。上田様「OK、それで契約します！」。4/16(水)に契約手続きで来店予定。LINEだけで価格交渉から成約まで完了した好事例。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0076", "negotiation_id": "N0593", "store_id": "S008", "customer_name": "中島翔太", "assigned_user_name": "井上大輔", "activity_type": "電話（受信）", "activity_date": "2026-04-05 10:00:00", "subject": "問合せ：アルファード 2023年式", "body": "中島様より入電。アルファード 2023年式について。「子供が2人いてミニバンが必要。新車は納期が長いから中古で探している」とのこと。予算250万円。現車フリード（2020年式）の下取りも希望。4/8(火)来店。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0077", "negotiation_id": "N0593", "store_id": "S008", "customer_name": "中島翔太", "assigned_user_name": "井上大輔", "activity_type": "来店対応", "activity_date": "2026-04-08 14:00:00", "subject": "来店・家族ニーズ丁寧にヒアリング", "body": "中島様お一人で来店。アルファードの実車確認。3列目シートの使い勝手、チャイルドシート2台設置のシミュレーション実施。フリードからの乗り換えポイント（室内空間の広さ、乗り心地の違い）を比較説明。下取りフリード査定→159万円。車両234万円との差額75万円。予算内に収まり好感触。「奥さんにLINEで写真送っていいですか？」とスマホで車内外を撮影。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0078", "negotiation_id": "N0593", "store_id": "S008", "customer_name": "中島翔太", "assigned_user_name": "井上大輔", "activity_type": "電話（受信）", "activity_date": "2026-04-10 12:00:00", "subject": "奥様からの追加質問", "body": "中島様の奥様より電話。「主人から写真をもらったのですが、傷はないですか？色は白で合っていますか？後ろの座席にDVDプレーヤーは付いていますか？」→外装の状態（小キズ1箇所を板金済み）、ホワイトパールクリスタルシャイン色、後席モニター付きであることを説明。「子供が退屈しないのでいいですね。主人に購入OKと伝えます」とのこと。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0079", "negotiation_id": "N0593", "store_id": "S008", "customer_name": "中島翔太", "assigned_user_name": "井上大輔", "activity_type": "契約手続き", "activity_date": "2026-04-15 14:00:00", "subject": "契約完了", "body": "中島様来店、契約完了。車両234万円、下取りフリード159万円、差額75万円を現金払い。保険の切替もご提案→検討中。納車4/25(金)予定。チャイルドシートの取付位置もアドバイス済み。", "created_at": "2026-04-07 21:17:43.495000"}'),
  ('{"activity_id": "ACT0080", "negotiation_id": "N0604", "store_id": "S009", "customer_name": "久保田翔", "assigned_user_name": "山本直樹", "activity_type": "Web問合せ", "activity_date": "2026-03-29 12:00:00", "subject": "Web問合せ受信：トヨタ アルファード", "body": "久保田翔様よりWebフォーム経由で問合せ。トヨタ アルファードに興味あり。現在の車からの乗り換え検討中。予算は416万円以内。平日夕方か土日の来店希望。翌営業日に電話でフォロー予定。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0081", "negotiation_id": "N0604", "store_id": "S004", "customer_name": "小松隆", "assigned_user_name": "藤田康平", "activity_type": "電話（発信）", "activity_date": "2026-03-31 08:45:00", "subject": "フォローコール", "body": "小松隆様へ架電。先日ご来店いただいた日産 ノートのご検討状況を確認。「まだ家族と相談中」とのこと。在庫状況として、同グレードの問合せが増えていることをお伝え。週末までにご回答いただける見込み。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0082", "negotiation_id": "N0604", "store_id": "S008", "customer_name": "片桐美咲", "assigned_user_name": "小林大輔", "activity_type": "電話（発信）", "activity_date": "2026-03-04 09:00:00", "subject": "在庫入荷のご連絡", "body": "片桐美咲様へ架電。以前お探しだったスバル フォレスターの新しい在庫が入荷したことをご連絡。走行距離や年式、グレードの詳細をお伝え。「ぜひ見てみたい」とのことで、来店アポを調整。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0083", "negotiation_id": "N0604", "store_id": "S006", "customer_name": "大西康平", "assigned_user_name": "石井由美", "activity_type": "来店対応", "activity_date": "2026-03-31 10:00:00", "subject": "再来店・家族同伴での確認", "body": "大西康平様ご家族で再来店。日産 ノートの実車をご家族にも確認いただく。ご家族全員の意見を聞き、荷室の広さや安全装備について詳しく説明。見積りの最終調整を行い、値引き後の価格で合意に近づく。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0084", "negotiation_id": "N0607", "store_id": "S007", "customer_name": "木下大輔", "assigned_user_name": "渡辺美穂", "activity_type": "紹介", "activity_date": "2026-03-13 16:00:00", "subject": "既存顧客からの紹介案件", "body": "既存顧客からの紹介で木下大輔様の情報を受領。スバル フォレスターに興味ありとのこと。架電しアポ調整。紹介元の顧客には紹介謝礼をご案内済み。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0085", "negotiation_id": "N0607", "store_id": "S004", "customer_name": "山本裕子", "assigned_user_name": "小林大輔", "activity_type": "社内メモ", "activity_date": "2026-03-19 19:00:00", "subject": "商談状況の共有", "body": "山本裕子様のスズキ ジムニー商談について店長と共有。価格交渉の余地と競合状況を分析。今後のフォロー方針を決定。顧客の温度感は中程度、継続的なフォローが必要と判断。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0086", "negotiation_id": "N0607", "store_id": "S002", "customer_name": "星野沙織", "assigned_user_name": "藤田康平", "activity_type": "来店対応", "activity_date": "2026-04-17 11:15:00", "subject": "来店ヒアリング・車両確認", "body": "星野沙織様来店。ホンダ ヴェゼルの実車を確認。内装の状態に満足された様子。試乗を実施し、「走りが良い」と好感触。見積書を作成し、総額495万円（税込）で提示。下取り査定も実施。「少し検討したい」とのことで、翌週にご連絡いただく約束。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0087", "negotiation_id": "N0607", "store_id": "S008", "customer_name": "谷口明美", "assigned_user_name": "森田沙織", "activity_type": "Web問合せ", "activity_date": "2026-04-13 19:30:00", "subject": "Web問合せ受信：ホンダ ヴェゼル", "body": "谷口明美様よりWebフォーム経由で問合せ。ホンダ ヴェゼルに興味あり。現在の車からの乗り換え検討中。予算は270万円以内。平日夕方か土日の来店希望。翌営業日に電話でフォロー予定。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0088", "negotiation_id": "N0610", "store_id": "S001", "customer_name": "黒田麻衣", "assigned_user_name": "高橋健一", "activity_type": "LINE", "activity_date": "2026-04-21 15:00:00", "subject": "LINE：値引き交渉", "body": "黒田麻衣様よりLINE。「マツダ CX-5ですが、318万円にしてもらえませんか？」との交渉。翌朝店長と相談の上回答する旨返信。競合他社の価格も確認中。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0089", "negotiation_id": "N0610", "store_id": "S001", "customer_name": "森下真由美", "assigned_user_name": "石井由美", "activity_type": "電話（受信）", "activity_date": "2026-03-03 16:30:00", "subject": "納車後フォロー", "body": "森下真由美様より入電。先日納車したトヨタ プリウスの調子を確認。「快適に乗っています」とのこと。オイル交換の時期についてご質問あり→次回点検時に実施する旨ご案内。知人への紹介もいただける可能性あり。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0090", "negotiation_id": "N0610", "store_id": "S009", "customer_name": "藤原康平", "assigned_user_name": "加藤明美", "activity_type": "紹介", "activity_date": "2026-03-05 19:00:00", "subject": "既存顧客からの紹介案件", "body": "既存顧客からの紹介で藤原康平様の情報を受領。スバル フォレスターに興味ありとのこと。架電しアポ調整。紹介元の顧客には紹介謝礼をご案内済み。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0091", "negotiation_id": "N0610", "store_id": "S002", "customer_name": "久保田翔", "assigned_user_name": "高橋健一", "activity_type": "LINE", "activity_date": "2026-04-02 09:45:00", "subject": "LINE：値引き交渉", "body": "久保田翔様よりLINE。「スズキ ジムニーですが、181万円にしてもらえませんか？」との交渉。翌朝店長と相談の上回答する旨返信。競合他社の価格も確認中。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0092", "negotiation_id": "N0615", "store_id": "S004", "customer_name": "瀬戸浩二", "assigned_user_name": "小林翔太", "activity_type": "来店対応", "activity_date": "2026-04-26 19:15:00", "subject": "再来店・家族同伴での確認", "body": "瀬戸浩二様ご家族で再来店。ホンダ フィットの実車をご家族にも確認いただく。ご家族全員の意見を聞き、荷室の広さや安全装備について詳しく説明。見積りの最終調整を行い、値引き後の価格で合意に近づく。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0093", "negotiation_id": "N0615", "store_id": "S006", "customer_name": "瀬戸浩二", "assigned_user_name": "伊藤裕太", "activity_type": "来店対応", "activity_date": "2026-04-03 20:45:00", "subject": "再来店・家族同伴での確認", "body": "瀬戸浩二様ご家族で再来店。スバル フォレスターの実車をご家族にも確認いただく。ご家族全員の意見を聞き、荷室の広さや安全装備について詳しく説明。見積りの最終調整を行い、値引き後の価格で合意に近づく。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0094", "negotiation_id": "N0615", "store_id": "S007", "customer_name": "中田裕子", "assigned_user_name": "加藤明美", "activity_type": "電話（受信）", "activity_date": "2026-03-25 08:00:00", "subject": "初回問合せ：トヨタ プリウスについて", "body": "中田裕子様より入電。Webで掲載中のトヨタ プリウスについて問合せ。現在の車からの乗り換えを検討中。予算は419万円前後。通勤と週末の買い物に使用予定。下取りも検討したいとのこと。来店日程を調整し、アポ確定。", "created_at": "2026-04-07 21:15:46.102000"}'),
