  ('{"activity_id": "ACT0123", "negotiation_id": "N0631", "store_id": "S006", "customer_name": "安藤直樹", "assigned_user_name": "小林大輔", "activity_type": "来店対応", "activity_date": "2026-03-28 18:00:00", "subject": "再来店・家族同伴での確認", "body": "安藤直樹様ご家族で再来店。トヨタ アクアの実車をご家族にも確認いただく。ご家族全員の意見を聞き、荷室の広さや安全装備について詳しく説明。見積りの最終調整を行い、値引き後の価格で合意に近づく。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0124", "negotiation_id": "N0636", "store_id": "S002", "customer_name": "谷口明美", "assigned_user_name": "森田沙織", "activity_type": "来店対応", "activity_date": "2026-04-15 12:15:00", "subject": "来店ヒアリング・車両確認", "body": "谷口明美様来店。トヨタ アクアの実車を確認。内装の状態に満足された様子。試乗を実施し、「走りが良い」と好感触。見積書を作成し、総額161万円（税込）で提示。下取り査定も実施。「少し検討したい」とのことで、翌週にご連絡いただく約束。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0125", "negotiation_id": "N0636", "store_id": "S005", "customer_name": "岡本沙織", "assigned_user_name": "小林翔太", "activity_type": "Web問合せ", "activity_date": "2026-04-02 10:45:00", "subject": "Web問合せ受信：スズキ ジムニー", "body": "岡本沙織様よりWebフォーム経由で問合せ。スズキ ジムニーに興味あり。現在の車からの乗り換え検討中。予算は142万円以内。平日夕方か土日の来店希望。翌営業日に電話でフォロー予定。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0126", "negotiation_id": "N0636", "store_id": "S004", "customer_name": "木下大輔", "assigned_user_name": "中村恵子", "activity_type": "電話（受信）", "activity_date": "2026-04-17 13:15:00", "subject": "納車後フォロー", "body": "木下大輔様より入電。先日納車したトヨタ プリウスの調子を確認。「快適に乗っています」とのこと。オイル交換の時期についてご質問あり→次回点検時に実施する旨ご案内。知人への紹介もいただける可能性あり。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0127", "negotiation_id": "N0636", "store_id": "S009", "customer_name": "安藤直樹", "assigned_user_name": "佐藤花子", "activity_type": "LINE", "activity_date": "2026-03-15 19:15:00", "subject": "LINE：値引き交渉", "body": "安藤直樹様よりLINE。「スズキ ジムニーですが、285万円にしてもらえませんか？」との交渉。翌朝店長と相談の上回答する旨返信。競合他社の価格も確認中。", "created_at": "2026-04-07 21:15:46.102000"}'),
