  ('{"activity_id": "ACT0246", "negotiation_id": "N0737", "store_id": "S007", "customer_name": "寺田直樹", "assigned_user_name": "森田沙織", "activity_type": "LINE", "activity_date": "2026-03-06 13:30:00", "subject": "LINE：値引き交渉", "body": "寺田直樹様よりLINE。「トヨタ プリウスですが、481万円にしてもらえませんか？」との交渉。翌朝店長と相談の上回答する旨返信。競合他社の価格も確認中。", "created_at": "2026-04-07 21:15:46.102000"}'),
