  ('{"activity_id": "ACT0248", "negotiation_id": "N0740", "store_id": "S008", "customer_name": "前田翔太", "assigned_user_name": "松本美咲", "activity_type": "電話（発信）", "activity_date": "2026-03-21 16:15:00", "subject": "在庫入荷のご連絡", "body": "前田翔太様へ架電。以前お探しだったホンダ フィットの新しい在庫が入荷したことをご連絡。走行距離や年式、グレードの詳細をお伝え。「ぜひ見てみたい」とのことで、来店アポを調整。", "created_at": "2026-04-07 21:15:46.102000"}'),
