  ('{"activity_id": "ACT0250", "negotiation_id": "N0740", "store_id": "S007", "customer_name": "佐野隆", "assigned_user_name": "森田沙織", "activity_type": "紹介", "activity_date": "2026-04-17 20:45:00", "subject": "既存顧客からの紹介案件", "body": "既存顧客からの紹介で佐野隆様の情報を受領。日産 ノートに興味ありとのこと。架電しアポ調整。紹介元の顧客には紹介謝礼をご案内済み。", "created_at": "2026-04-07 21:15:46.102000"}');

