  ('{"activity_id": "ACT0393", "negotiation_id": "N0842", "store_id": "S010", "customer_name": "遠藤裕子", "assigned_user_name": "小林翔太", "activity_type": "契約手続き", "activity_date": "2026-04-06 12:15:00", "subject": "契約完了", "body": "遠藤裕子様来店、電子売契にて契約完了。トヨタ ハリアーの総額318万円。支払方法確定。納車予定日を調整。保険の切替についてもご案内済み。380様「対応が丁寧で安心して購入できた」とコメント。", "created_at": "2026-04-07 21:15:46.102000"}'),
  ('{"activity_id": "ACT0394", "negotiation_id": "N0842", "store_id": "S002", "customer_name": "小松隆", "assigned_user_name": "佐藤花子", "activity_type": "電話（受信）", "activity_date": "2026-04-20 09:15:00", "subject": "初回問合せ：ホンダ フィットについて", "body": "小松隆様より入電。Webで掲載中のホンダ フィットについて問合せ。現在の車からの乗り換えを検討中。予算は472万円前後。通勤と週末の買い物に使用予定。下取りも検討したいとのこと。来店日程を調整し、アポ確定。", "created_at": "2026-04-07 21:15:46.102000"}'),
