  ('{"activity_id": "ACT1451", "negotiation_id": "N0963", "store_id": "S023", "customer_name": "新井彩", "assigned_user_name": "平野真理", "activity_type": "電話（受信）", "activity_date": "2026-04-02 14:15:00", "subject": "価格の再確認", "body": "新井彩様より入電。トヨタ プリウスについて問合せ。現在の車からの乗り換えを検討中。予算は585万円前後。通勤と週末の買い物に使用予定。来店日程を調整し、アポ確定。", "created_at": "2026-04-07 21:15:46.102000"}'),
